import sys, math

def solve() -> None:
    data = list(map(int, sys.stdin.buffer.read().split()))
    it = iter(data)
    t = next(it)
    out = []
    for _ in range(t):
        n = next(it)
        cnt = [0] * 30
        for _ in range(n):
            v = next(it)
            b = 0
            while v:
                if v & 1:
                    cnt[b] += 1
                v >>= 1
                b += 1
        g = 0
        for c in cnt:
            if c:
                g = math.gcd(g, c)
        if g == 0:
            out.append(' '.join(str(i) for i in range(1, n + 1)))
        else:
            divs = []
            i = 1
            while i * i <= g:
                if g % i == 0:
                    divs.append(i)
                    if i != g // i:
                        divs.append(g // i)
                i += 1
            divs.sort()
            out.append(' '.join(str(d) for d in divs))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

