import sys

def solve() -> None:
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    t = int(next(it))
    out_lines = []
    for _ in range(t):
        x1 = int(next(it)); p1 = int(next(it))
        x2 = int(next(it)); p2 = int(next(it))

        d1 = len(str(x1))
        d2 = len(str(x2))

        total1 = d1 + p1
        total2 = d2 + p2

        if total1 > total2:
            out_lines.append('>')
        elif total1 < total2:
            out_lines.append('<')
        else:
            # same total length, adjust by the difference in zeros
            if p1 > p2:
                # multiply x2 by 10^(p1-p2)
                diff = p1 - p2
                x2_adj = x2 * (10 ** diff)
                x1_adj = x1
            elif p2 > p1:
                diff = p2 - p1
                x1_adj = x1 * (10 ** diff)
                x2_adj = x2
            else:
                x1_adj = x1
                x2_adj = x2

            if x1_adj > x2_adj:
                out_lines.append('>')
            elif x1_adj < x2_adj:
                out_lines.append('<')
            else:
                out_lines.append('=')

    sys.stdout.write('\n'.join(out_lines))

