def solve() -> None:
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    t = int(next(it))
    out_lines = []
    for _ in range(t):
        s = next(it)
        T = next(it)
        cnt = [0] * 26
        for ch in s:
            cnt[ord(ch) - 97] += 1

        if T == "abc" and cnt[0] > 0 and cnt[1] > 0 and cnt[2] > 0:
            # special ordering: a's, c's, b's, then the rest in normal order
            res = []
            res.append('a' * cnt[0])
            res.append('c' * cnt[2])
            res.append('b' * cnt[1])
            for i in range(3, 26):
                if cnt[i]:
                    res.append(chr(i + 97) * cnt[i])
            out_lines.append(''.join(res))
        else:
            # normal sorted order
            res = []
            for i in range(26):
                if cnt[i]:
                    res.append(chr(i + 97) * cnt[i])
            out_lines.append(''.join(res))
    sys.stdout.write('\n'.join(out_lines))

