def solve() -> None:
    data = sys.stdin.read().splitlines()
    if not data:
        return
    t = int(data[0])
    out_lines = []
    for i in range(1, t + 1):
        s = data[i].strip()
        n = len(s)
        if n % 2 == 0 and s[:n // 2] == s[n // 2:]:
            out_lines.append("YES")
        else:
            out_lines.append("NO")
    sys.stdout.write("\n".join(out_lines))

